patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 19b95cf473e9..d9619b51ff93 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -7776,6 +7776,7 @@ void BoUpSLP::buildTree_rec(ArrayRef<Value *> VL, unsigned Depth,
 }

 unsigned BoUpSLP::canMapToVector(Type *T) const {
+  if (!T) return 0; // Early exit if the type is null.
   unsigned N = 1;
   Type *EltTy = T;

@@ -7785,13 +7786,16 @@ unsigned BoUpSLP::canMapToVector(Type *T) const {
       for (const auto *Ty : ST->elements())
         if (Ty != *ST->element_begin())
           return 0;
+      if (ST->getNumElements() == 0) return 0; // Prevent zero vectorization factor
       N *= ST->getNumElements();
       EltTy = *ST->element_begin();
     } else if (auto *AT = dyn_cast<ArrayType>(EltTy)) {
+      if (AT->getNumElements() == 0) return 0; // Prevent zero vectorization factor
       N *= AT->getNumElements();
       EltTy = AT->getElementType();
     } else {
       auto *VT = cast<FixedVectorType>(EltTy);
+      if (VT->getNumElements() == 0) return 0; // Prevent zero vectorization factor
       N *= VT->getNumElements();
       EltTy = VT->getElementType();
     }

